SimulationData binary_read( Inputs in )
{
	SimulationData SD;

	const char * fname = "XS_data.dat";
	printf("Reading all data structures from binary file %s...\n", fname);

	FILE * fp = fopen(fname, "r");
	assert(fp != NULL);

	// Read SimulationData Object. Include pointers, even though we won't be using them.
	size_t ret = fread(&SD, sizeof(SimulationData), 1, fp);
	assert(ret == 1);

	// Allocate space for arrays on heap
	SD.num_nucs = (int *) malloc(SD.length_num_nucs * sizeof(int));
	SD.concs = (double *) malloc(SD.length_concs * sizeof(double));
	SD.mats = (int *) malloc(SD.length_mats * sizeof(int));
	SD.nuclide_grid = (NuclideGridPoint *) malloc(SD.length_nuclide_grid * sizeof(NuclideGridPoint));
	SD.index_grid = (int *) malloc( SD.length_index_grid * sizeof(int));
	SD.unionized_energy_array = (double *) malloc( SD.length_unionized_energy_array * sizeof(double));

	// Read heap arrays into SimulationData Object
	ret = fread(SD.num_nucs, sizeof(int), SD.length_num_nucs, fp);
	assert(ret == SD.length_num_nucs);

	ret = fread(SD.concs, sizeof(double), SD.length_concs, fp);
	assert(ret == SD.length_concs);

	ret = fread(SD.mats, sizeof(int), SD.length_mats, fp);
	assert(ret == SD.length_mats);

	ret = fread(SD.nuclide_grid, sizeof(NuclideGridPoint), SD.length_nuclide_grid, fp);
	assert(ret == SD.length_nuclide_grid);

	ret = fread(SD.index_grid, sizeof(int), SD.length_index_grid, fp);
	assert(ret == SD.length_index_grid);

	ret = fread(SD.unionized_energy_array, sizeof(double), SD.length_unionized_energy_array, fp);
	assert(ret == SD.length_unionized_energy_array);

	fclose(fp);

	return SD;
}
